import{_ as a,c as e,o as m,b as t}from"./app.648408b7.js";const o='{"title":"\u0412\u0441\u0442\u0443\u043F\u043B\u0435\u043D\u0438\u0435","description":"","frontmatter":{"title":"\u0412\u0441\u0442\u0443\u043F\u043B\u0435\u043D\u0438\u0435","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 1.","tags":"vim-1","date":"2021-03-02T00:00:00.000Z"},"headers":[{"level":2,"title":"\u0423\u043C\u0438\u0440\u043E\u0442\u0432\u043E\u0440\u044F\u044E\u0449\u0430\u044F \u043C\u043E\u043B\u0438\u0442\u0432\u0430 \u043A \u0428\u0430\u043D\u043A\u0430\u0440\u0435 (\u015Aa\u1E45kara)","slug":"\u0443\u043C\u0438\u0440\u043E\u0442\u0432\u043E\u0440\u044F\u044E\u0449\u0430\u044F-\u043C\u043En\u0438\u0442\u0432\u0430-\u043A-\u0448\u0430\u043D\u043A\u0430\u0440\u0435-sankara"},{"level":2,"title":"\u041F\u0440\u0438\u0447\u0438\u043D\u044B \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0438\u044F \u044D\u0442\u043E\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F","slug":"\u043F\u0440\u0438\u0447\u0438\u043D\u044B-\u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0438\u044F-\u044D\u0442\u043E\u0433\u043E-\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F"},{"level":2,"title":"\u041E\u0442\u043A\u0440\u044B\u0442\u0438\u0435 \u0428\u0438\u0432\u0430\u0441\u0443\u0442\u0440","slug":"\u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435-\u0448\u0438\u0432\u0430\u0441\u0443\u0442\u0440"}],"relativePath":"texts/shiva-sutra-vimarshini/1/start/index.md"}',i={},r=t('<div class="stanza"><h2 id="\u0443\u043C\u0438\u0440\u043E\u0442\u0432\u043E\u0440\u044F\u044E\u0449\u0430\u044F-\u043C\u043En\u0438\u0442\u0432\u0430-\u043A-\u0448\u0430\u043D\u043A\u0430\u0440\u0435-sankara" tabindex="-1">\u0423\u043C\u0438\u0440\u043E\u0442\u0432\u043E\u0440\u044F\u044E\u0449\u0430\u044F \u043C\u043E\u043B\u0438\u0442\u0432\u0430 \u043A \u0428\u0430\u043D\u043A\u0430\u0440\u0435 (\u015Aa\u1E45kara) <a class="header-anchor" href="#\u0443\u043C\u0438\u0440\u043E\u0442\u0432\u043E\u0440\u044F\u044E\u0449\u0430\u044F-\u043C\u043En\u0438\u0442\u0432\u0430-\u043A-\u0448\u0430\u043D\u043A\u0430\u0440\u0435-sankara" aria-hidden="true">#</a></h2><p class="sans">\u0930\u0941\u0926\u094D\u0930\u0915\u094D\u0937\u0947\u0924\u094D\u0930\u091C\u094D\u091E\u0935\u0930\u094D\u0917\u0903 \u0938\u092E\u0941\u0926\u092F\u0924\u093F \u092F\u0924\u094B \u092F\u0924\u094D\u0930 \u0935\u093F\u0936\u094D\u0930\u093E\u0928\u094D\u0924\u093F\u092E\u0943\u091A\u094D\u091B\u0947\u0926\u094D-<br> \u092F\u0924\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u0902 \u092F\u0938\u094D\u092F \u0935\u093F\u0936\u094D\u0935\u0902 \u0938\u094D\u092B\u0941\u0930\u093F\u0924\u092E\u092F\u092E\u093F\u092F\u0926\u094D\u092F\u0928\u094D\u092E\u092F\u0902 \u0935\u093F\u0936\u094D\u0935\u092E\u0947\u0924\u0924\u094D\u0964<br> \u0938\u094D\u0935\u093E\u091A\u094D\u091B\u0928\u094D\u0926\u094D\u092F\u093E\u0928\u0928\u094D\u0926\u0935\u0943\u0928\u094D\u0926\u094B\u091A\u094D\u091B\u0932\u0926\u092E\u0943\u0924\u092E\u092F\u093E\u0928\u0941\u0924\u094D\u0924\u0930\u0938\u094D\u092A\u0928\u094D\u0926\u0924\u0924\u094D\u0924\u094D\u0935\u0902<br> \u091A\u0948\u0924\u0928\u094D\u092F\u0902 \u0936\u093E\u0919\u094D\u0915\u0930\u0902 \u0924\u091C\u094D\u091C\u092F\u0924\u093F \u092F\u0926\u0916\u093F\u0932\u0902 \u0926\u094D\u0935\u0948\u0924\u092D\u093E\u0938\u093E\u0926\u094D\u0935\u092F\u093E\u0924\u094D\u092E\u0965</p><p class="trans">Rudrak\u1E63etraj\xF1avarga\u1E25 samudayati yato yatra vi\u015Br\u0101ntim\u1E5Bcched-<br> yattattva\u1E41 yasya vi\u015Bva\u1E41 sphuritamayamiyadyanmaya\u1E41 vi\u015Bvametat|<br> Sv\u0101cchandy\u0101nandav\u1E5Bndocchaladam\u1E5Btamay\u0101nuttaraspandatattva\u1E41<br> caitanya\u1E41 \u015B\u0101\u1E45kara\u1E41 tajjayati yadakhila\u1E41 dvaitabh\u0101s\u0101dvay\u0101tma||</p><p>\u042D\u0442\u043E <em>(tad)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(caitanyam)</em> \u0428\u0430\u043D\u043A\u0430\u0440\u044B <em>(\u015B\u0101\u1E45karam)</em> \u0442\u043E\u0440\u0436\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043F\u043E\u0431\u0435\u0434\u0443 --\u0442.\u0435. \u043E\u043D\u043E &quot;\u043F\u043E\u0431\u0435\u0434\u043E\u043D\u043E\u0441\u043D\u043E\u0435&quot;-- <em>(jayati)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(yad)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E <em>(akhilam)</em> \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(advaya-\u0101tma)</em>, [\u043D\u043E \u0438\u043C\u0435\u0435\u0442] \u0432\u043D\u0435\u0448\u043D\u0438\u0439 \u0432\u0438\u0434, \u0438\u043B\u0438 \u0441\u0438\u044F\u043D\u0438\u0435 <em>(bh\u0101sa)</em> \u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(dvaita)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(yad)</em> [\u0435\u0441\u0442\u044C] \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(tattvam)</em>, \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E <em>(yatas)</em> \u0432\u0438\u0434, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F\u0430 <em>(varga\u1E25)</em> Rudra-s <em>(rudra)</em> [\u0438] K\u1E63etraj\xF1a-s <em>(k\u1E63etraj\xF1a)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(samudayati)</em>, [\u0438] \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C <em>(yatra)</em> \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u043A \u043F\u043E\u043A\u043E\u044E <em>(vi\u015Br\u0101ntim \u1E5Bcchet)</em>, \u0447\u044C\u044F <em>(yasya)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bvam)</em> \u0441\u043E\u0441\u0442\u043E\u0438\u0442 <em>(mayam)</em> \u0438\u0437 \u043F\u0443\u043B\u044C\u0441\u0430\u0446\u0438\u0439 <em>(sphurita)</em> --\u0438\u043B\u0438 \u0442\u0430\u043A\u0436\u0435, \u0430\u043B\u044C\u0442\u0435\u0440\u043D\u0430\u0442\u0438\u0432\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043C\u043E\u0433 \u0431\u044B \u0431\u044B\u0442\u044C &quot;\u0447\u044C\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u0432\u0441\u043F\u044B\u0445\u0438\u0432\u0430\u0435\u0442 \u0432 \u043F\u043E\u043B\u0435 \u0437\u0440\u0435\u043D\u0438\u044F \u043E\u0442\u0442\u0443\u0434\u0430&quot;--, \u0447\u044C\u044F <em>(yasya)</em> \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u043D\u043E\u0441\u0442\u044C <em>(iyat)</em> [\u0435\u0441\u0442\u044C] \u044D\u0442\u0430 [\u0441\u0430\u043C\u0430\u044F] <em>(etad)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bvam)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u043E\u043B\u043D\u0430 <em>(mayam)</em> \u042D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u044D\u0442\u043E\u0433\u043E \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(yad)</em>. [\u041A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u044D\u0442\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0428\u0430\u043D\u043A\u0430\u0440\u044B \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u043C <em>(tattvam)</em> \u0418\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0412\u0438\u0431\u0440\u0430\u0446\u0438\u0438 <em>(spanda)</em> \u0410\u043D\u0443\u0442\u0442\u0430\u0440\u0430 (Anuttara) --\u0442.\u0435. &quot;\u0428\u0438\u0432\u044B, \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0430&quot;-- <em>(anuttara)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u043C <em>(maya)</em> \u0438\u0437 \u041D\u0435\u043A\u0442\u0430\u0440\u0430 <em>(am\u1E5Bta)</em>, \u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E <em>(ucchalat)</em> \u0438\u0437 \u041C\u0430\u0441\u0441\u044B <em>(v\u1E5Bnda)</em> \u0421\u0432\u043E\u0431\u043E\u0434\u044B <em>(sv\u0101cchandya)</em> \u0438 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u0101nanda)</em>.</p></div><div class="stanza"><h2 id="\u043F\u0440\u0438\u0447\u0438\u043D\u044B-\u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0438\u044F-\u044D\u0442\u043E\u0433\u043E-\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F" tabindex="-1">\u041F\u0440\u0438\u0447\u0438\u043D\u044B \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0438\u044F \u044D\u0442\u043E\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F <a class="header-anchor" href="#\u043F\u0440\u0438\u0447\u0438\u043D\u044B-\u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0438\u044F-\u044D\u0442\u043E\u0433\u043E-\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F" aria-hidden="true">#</a></h2><p class="sans">\u0905\u0938\u093E\u092E\u091E\u094D\u091C\u0938\u094D\u092F\u092E\u093E\u0932\u094B\u091A\u094D\u092F \u0935\u0943\u0924\u094D\u0924\u0940\u0928\u093E\u092E\u093F\u0939 \u0924\u0924\u094D\u0924\u094D\u0935\u0924\u0903\u0964<br> \u0936\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u0902 \u0935\u094D\u092F\u093E\u0915\u0930\u094B\u092E\u093F \u0917\u0941\u0930\u094D\u0935\u093E\u092E\u094D\u0928\u093E\u092F\u0935\u093F\u0917\u093E\u0928\u0924\u0903\u0965</p><p class="trans">As\u0101ma\xF1jasyam\u0101locya v\u1E5Btt\u012Bn\u0101miha tattvata\u1E25|<br> \u015Aivas\u016Btra\u1E41 vy\u0101karomi gurv\u0101mn\u0101yavig\u0101nata\u1E25||</p><p>\u041E\u0442\u043C\u0435\u0442\u0438\u0432 <em>(\u0101locya)</em> \u043D\u0435\u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0435 <em>(as\u0101ma\xF1jasyam)</em> \u0432 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F\u0445 <em>(v\u1E5Btt\u012Bn\u0101m)</em> \u0432 \u044D\u0442\u043E \u0432\u0440\u0435\u043C\u044F <em>(iha)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 \u043D\u0435 \u0441\u043E\u0433\u043B\u0430\u0441\u0443\u044E\u0442\u0441\u044F <em>(vig\u0101nata\u1E25)</em> \u0441\u043E \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \u0422\u0440\u0430\u0434\u0438\u0446\u0438\u0435\u0439 <em>(\u0101mn\u0101ya)</em> \u0413\u0443\u0440\u0443, \u0438\u043B\u0438 \u041C\u0430\u0441\u0442\u0435\u0440\u043E\u0432 <em>(guru)</em>, \u042F \u0438\u0437\u043B\u0430\u0433\u0430\u044E <em>(vy\u0101karomi)</em> \u015Aivas\u016Btra-s <em>(\u015Bivas\u016Btram)</em> \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0438\u0445 \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u043C \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435\u043C <em>(tattvatas)</em>.</p></div><div class="stanza"><h2 id="\u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435-\u0448\u0438\u0432\u0430\u0441\u0443\u0442\u0440" tabindex="-1">\u041E\u0442\u043A\u0440\u044B\u0442\u0438\u0435 \u0428\u0438\u0432\u0430\u0441\u0443\u0442\u0440 <a class="header-anchor" href="#\u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435-\u0448\u0438\u0432\u0430\u0441\u0443\u0442\u0440" aria-hidden="true">#</a></h2><p class="sans">\u0907\u0939 \u0915\u0936\u094D\u091A\u093F\u091A\u094D\u091B\u0915\u094D\u0924\u093F\u092A\u093E\u0924\u0935\u0936\u094B\u0928\u094D\u092E\u093F\u0937\u0928\u094D\u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u092D\u0915\u094D\u0924\u094D\u092F\u0924\u093F\u0936\u092F\u093E\u0926\u0928\u0919\u094D\u0917\u0940\u0915\u0943\u0924\u093E\u0927\u0930\u0926\u0930\u094D\u0936\u0928\u0938\u094D\u0925\u0928\u093E\u0917\u092C\u094B\u0927\u094D\u092F\u093E\u0926\u093F\u0938\u093F\u0926\u094D\u0927\u093E\u0926\u0947\u0936\u0928\u0903 \u0936\u093F\u0935\u093E\u0930\u093E\u0927\u0928\u092A\u0930\u0903 \u092A\u093E\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u0928\u093E\u0928\u093E\u092F\u094B\u0917\u093F\u0928\u0940\u0938\u093F\u0926\u094D\u0927\u0938\u0924\u094D\u0938\u092E\u094D\u092A\u094D\u0930\u0926\u093E\u092F\u092A\u0935\u093F\u0924\u094D\u0930\u093F\u0924\u0939\u0943\u0926\u092F\u0903 \u0936\u094D\u0930\u0940\u092E\u0939\u093E\u0926\u0947\u0935\u0917\u093F\u0930\u094C \u092E\u0939\u093E\u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u0903 \u0936\u094D\u0930\u0940\u092E\u093E\u0928\u094D \u0935\u0938\u0941\u0917\u0941\u092A\u094D\u0924\u0928\u093E\u092E\u093E \u0917\u0941\u0930\u0941\u0930\u092D\u0935\u0924\u094D\u0964<br> \u0915\u0926\u093E\u091A\u093F\u091A\u094D\u091A\u093E\u0938\u094C \u0926\u094D\u0935\u0948\u0924\u0926\u0930\u094D\u0936\u0928\u093E\u0927\u093F\u0935\u093E\u0938\u093F\u0924\u092A\u094D\u0930\u093E\u092F\u0947 \u091C\u0940\u0935\u0932\u094B\u0915\u0947 \u0930\u0939\u0938\u094D\u092F\u0938\u092E\u094D\u092A\u094D\u0930\u0926\u093E\u092F\u094B \u092E\u093E \u0935\u093F\u091A\u094D\u091A\u0947\u0926\u0940\u0924\u094D\u092F\u093E\u0936\u092F\u0924\u094B\u093D\u0928\u0941\u091C\u093F\u0918\u0943\u0915\u094D\u0937\u093E\u092A\u0930\u0947\u0923 \u092A\u0930\u092E\u0936\u093F\u0935\u0947\u0928 \u0938\u094D\u0935\u092A\u094D\u0928\u0947\u093D\u0928\u0941\u0917\u094D\u0930\u0939\u094D\u092F\u094B\u0928\u094D\u092E\u093F\u0937\u093F\u0924\u092A\u094D\u0930\u0924\u093F\u092D\u0903 \u0915\u0943\u0924\u094B \u092F\u0925\u093E\u0924\u094D\u0930 \u092E\u0939\u0940\u092D\u0943\u0924\u093F \u092E\u0939\u0924\u093F \u0936\u093F\u0932\u093E\u0924\u0932\u0947 \u0930\u0939\u0938\u094D\u092F\u092E\u0938\u094D\u0924\u093F \u0924\u0926\u0927\u093F\u0917\u092E\u094D\u092F\u093E\u0928\u0941\u0917\u094D\u0930\u0939\u092F\u094B\u0917\u094D\u092F\u0947\u0937\u0941 \u092A\u094D\u0930\u0915\u093E\u0936\u092F\u0947\u0924\u093F\u0964 \u092A\u094D\u0930\u092C\u0941\u0926\u094D\u0927\u0936\u094D\u091A\u093E\u0938\u093E\u0935\u0928\u094D\u0935\u093F\u0937\u094D\u092F\u0902\u0938\u094D\u0924\u093E\u0902 \u092E\u0939\u0924\u0940\u0902 \u0936\u093F\u0932\u093E\u0902 \u0915\u0930\u0938\u094D\u092A\u0930\u094D\u0936\u0928\u092E\u093E\u0924\u094D\u0930\u092A\u0930\u093F\u0935\u0930\u094D\u0924\u0928\u0924\u0903 \u0938\u0902\u0935\u093E\u0926\u0940\u0915\u0943\u0924\u0938\u094D\u0935\u092A\u094D\u0928\u093E\u0902 \u092A\u094D\u0930\u0924\u094D\u092F\u0915\u094D\u0937\u0940\u0915\u0943\u0924\u094D\u092F\u0947\u092E\u093E\u0928\u093F \u0936\u093F\u0935\u094B\u092A\u0928\u093F\u0937\u0924\u094D\u0938\u0919\u094D\u0917\u094D\u0930\u0939\u0930\u0942\u092A\u093E\u0923\u093F \u0936\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u093E\u0923\u093F \u0924\u0924\u0903 \u0938\u092E\u093E\u0938\u0938\u093E\u0926\u0964 \u090F\u0924\u093E\u0928\u093F \u091A \u0938\u092E\u094D\u092F\u0917\u0927\u093F\u0917\u092E\u094D\u092F \u092D\u091F\u094D\u091F\u0936\u094D\u0930\u0940\u0915\u0932\u094D\u0932\u091F\u093E\u0926\u094D\u092F\u0947\u0937\u0941 \u0938\u091A\u094D\u091B\u093F\u0937\u094D\u092F\u0947\u0937\u0941 \u092A\u094D\u0930\u0915\u093E\u0936\u093F\u0924\u0935\u093E\u0928\u094D \u0938\u094D\u092A\u0928\u094D\u0926\u0915\u093E\u0930\u093F\u0915\u093E\u092D\u093F\u0936\u094D\u091A \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u0935\u093E\u0928\u094D\u0964 \u0924\u0924\u094D\u092A\u093E\u0930\u092E\u094D\u092A\u0930\u094D\u092F\u092A\u094D\u0930\u093E\u092A\u094D\u0924\u093E\u0928\u093F \u0938\u094D\u092A\u0928\u094D\u0926\u0938\u0942\u0924\u094D\u0930\u093E\u0923\u094D\u092F\u0938\u094D\u092E\u093E\u092D\u093F\u0903 \u0938\u094D\u092A\u0928\u094D\u0926\u0928\u093F\u0930\u094D\u0923\u092F\u0947 \u0938\u092E\u094D\u092F\u0917\u094D\u0928\u093F\u0930\u094D\u0923\u0940\u0924\u093E\u0928\u093F\u0964 \u0936\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u093E\u0923\u093F \u0924\u0941 \u0928\u093F\u0930\u094D\u0923\u0940\u092F\u0928\u094D\u0924\u0947\u0965<br> \u0924\u0924\u094D\u0930 \u092A\u094D\u0930\u0925\u092E\u0902 \u0928\u0930\u0947\u0936\u094D\u0935\u0930\u092D\u0947\u0926\u0935\u093E\u0926\u093F\u092A\u094D\u0930\u093E\u0924\u093F\u092A\u0915\u094D\u0937\u094D\u092F\u0947\u0923 \u091A\u0948\u0924\u0928\u094D\u092F\u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0924\u0903 \u0936\u093F\u0935 \u090F\u0935 \u0935\u093F\u0936\u094D\u0935\u0938\u094D\u092F\u093E\u0924\u094D\u092E\u0947\u0924\u094D\u092F\u093E\u0926\u093F\u0936\u0924\u093F\u2014</p><p class="trans">Iha ka\u015Bcicchaktip\u0101tava\u015Bonmi\u1E63anm\u0101he\u015Bvarabhaktyati\u015Bay\u0101dana\u1E45g\u012Bk\u1E5Bt\u0101dharadar\u015Banasthan\u0101gabodhy\u0101disiddh\u0101de\u015Bana\u1E25 \u015Biv\u0101r\u0101dhanapara\u1E25 p\u0101rame\u015Bvaran\u0101n\u0101yogin\u012Bsiddhasatsamprad\u0101yapavitritah\u1E5Bdaya\u1E25 \u015Br\u012Bmah\u0101devagirau mah\u0101m\u0101he\u015Bvara\u1E25 \u015Br\u012Bm\u0101n vasuguptan\u0101m\u0101 gururabhavat|<br> Kad\u0101cicc\u0101sau dvaitadar\u015Ban\u0101dhiv\u0101sitapr\u0101ye j\u012Bvaloke rahasyasamprad\u0101yo m\u0101 vicched\u012Bty\u0101\u015Bayato&#39;nujigh\u1E5Bk\u1E63\u0101pare\u1E47a parama\u015Bivena svapne&#39;nugrahyonmi\u1E63itapratibha\u1E25 k\u1E5Bto yath\u0101tra mah\u012Bbh\u1E5Bti mahati \u015Bil\u0101tale rahasyamasti tadadhigamy\u0101nugrahayogye\u1E63u prak\u0101\u015Bayeti|<br> Prabuddha\u015Bc\u0101s\u0101vanvi\u1E63ya\u1E41st\u0101\u1E41mahat\u012B\u1E41 \u015Bil\u0101\u1E41 karaspar\u015Banam\u0101traparivartanata\u1E25 sa\u1E41v\u0101d\u012Bk\u1E5Btasvapn\u0101\u1E41 pratyak\u1E63\u012Bk\u1E5Btyem\u0101ni \u015Bivopani\u1E63atsa\u1E45grahar\u016Bp\u0101\u1E47i \u015Bivas\u016Btr\u0101\u1E47i tata\u1E25 sam\u0101sas\u0101da|<br> Et\u0101ni ca samyagadhigamya bha\u1E6D\u1E6Da\u015Br\u012Bkalla\u1E6D\u0101dye\u1E63u sacchi\u1E63ye\u1E63u prak\u0101\u015Bitav\u0101n spandak\u0101rik\u0101bhi\u015Bca sa\u1E45g\u1E5Bh\u012Btav\u0101n|<br> Tatp\u0101ramparyapr\u0101pt\u0101ni spandas\u016Btr\u0101\u1E47yasm\u0101bhi\u1E25 spandanir\u1E47aye samyagnir\u1E47\u012Bt\u0101ni|<br> \u015Aivas\u016Btr\u0101\u1E47i tu nir\u1E47\u012Byante||<br> Tatra prathama\u1E41 nare\u015Bvarabhedav\u0101dipr\u0101tipaksye\u1E47a caitanyaparam\u0101rthata\u1E25 \u015Biva eva vi\u015Bvasy\u0101tmety\u0101di\u015Bati\u2014</p><p>\u0412 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435 <em>(iha)</em>, \u043D\u0430 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 <em>(\u015Br\u012B)</em> \u0433\u043E\u0440\u0435 <em>(girau)</em> Mah\u0101deva <em>(mah\u0101deva)</em>, \u043D\u0435\u043A\u0442\u043E <em>(ka\u015Bcid)</em>, \u0434\u043E\u0441\u0442\u043E\u0439\u043D\u044B\u0439 \u043F\u043E\u0447\u0442\u0435\u043D\u0438\u044F <em>(\u015Br\u012Bm\u0101n)</em> ,[\u0436\u0438\u043B]. \u0415\u0433\u043E \u0441\u0435\u0440\u0434\u0446\u0435 <em>(h\u1E5Bdaya\u1E25)</em> \u0431\u044B\u043B\u043E \u043E\u0447\u0438\u0449\u0435\u043D\u043E <em>(pavitrita)</em> \u0411\u043B\u0430\u0433\u043E\u0440\u043E\u0434\u043D\u043E\u0439 <em>(sat)</em> \u0422\u0440\u0430\u0434\u0438\u0446\u0438\u0435\u0439 <em>(samprad\u0101ya)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 <em>(n\u0101n\u0101)</em> \u0421\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u0445 \u0421\u0443\u0449\u0435\u0441\u0442\u0432 <em>(siddha)</em> \u0438 \u0419\u043E\u0433\u0438\u043D\u044C <em>(yogin\u012B)</em>, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0435\u0439 \u0412\u0435\u043B\u0438\u043A\u043E\u043C\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u0443 <em>(p\u0101rame\u015Bvara)</em>. \u041E\u043D \u0431\u044B\u043B \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D <em>(para\u1E25)</em> \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u044E <em>(\u0101r\u0101dhana)</em> \u0412\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u043C\u0443 <em>(\u015Biva)</em>. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0438\u0437\u0431\u044B\u0442\u043A\u0443 <em>(ati\u015Bay\u0101t)</em> \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0441\u0442\u0438 <em>(bhakti)</em> \u0412\u0435\u043B\u0438\u043A\u043E\u043C\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u0443 <em>(m\u0101he\u015Bvara)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F [\u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0441\u0442\u044C] \u0441\u0438\u044F\u043B\u0430 [\u0432 \u043D\u0435\u043C] <em>(unmi\u1E63at)</em>, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F <em>(va\u015Ba)</em> \u041D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044E <em>(p\u0101ta)</em> \u0421\u0438\u043B\u044B <em>(\u015Bakti)</em> --\u0442.\u0435. \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u041C\u0438\u043B\u043E\u0441\u0442\u0438--, (\u043E\u043D) \u0434\u0430\u0432\u0430\u043B \u0443\u0447\u0435\u043D\u0438\u0435 <em>(\u0101de\u015Bana\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043D\u0435 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u043B\u043E \u043C\u043D\u0435\u043D\u0438\u044E <em>(ana\u1E45g\u012Bk\u1E5Bta)</em> \u0442\u0430\u043A\u0438\u0445 \u0421\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u0445 \u0421\u0443\u0449\u0435\u0441\u0442\u0432 [\u0432 \u0411\u0443\u0434\u0434\u0438\u0437\u043C\u0435] <em>(siddha)</em>, \u043A\u0430\u043A \u041D\u0430\u0433\u0430\u0431\u043E\u0434\u0445\u0438 <em>(n\u0101gabodhi)</em> \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 <em>(\u0101di)</em>, \u0438\u043C\u0435\u0432\u0448\u0438\u0445 <em>(stha)</em> \u0431\u043E\u043B\u0435\u0435 \u043D\u0438\u0437\u043A\u0443\u044E <em>(adhara)</em> \u0442\u043E\u0447\u043A\u0443 \u0437\u0440\u0435\u043D\u0438\u044F <em>(dar\u015Bana)</em>. \u041E\u043D \u0431\u044B\u043B <em>(abhavat)</em> \u0432\u0435\u043B\u0438\u043A\u0438\u043C \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u044B\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(mah\u0101m\u0101he\u015Bvara\u1E25)</em> \u0438 \u0413\u0443\u0440\u0443 <em>(guru\u1E25)</em>. \u0415\u0433\u043E \u0438\u043C\u044F <em>(n\u0101m\u0101)</em> - \u0412\u0430\u0441\u0443\u0433\u0443\u043F\u0442\u0430 <em>(vasugupta)</em>.</p><p>\u0418 <em>(ca)</em> \u043E\u0434\u043D\u0430\u0436\u0434\u044B <em>(kad\u0101cid)</em>, \u0412\u0435\u043B\u0438\u043A\u0438\u0439 <em>(parama)</em> \u0428\u0438\u0432\u0430 <em>(\u015Bivena)</em>, \u0432\u043E\u0437\u043D\u0430\u043C\u0435\u0440\u0438\u0432\u0448\u0438\u0441\u044C <em>(pare\u1E47a)</em> \u043F\u0440\u043E\u044F\u0432\u0438\u0442\u044C \u0411\u043B\u0430\u0433\u043E\u0432\u043E\u043B\u0435\u043D\u0438\u0435 <em>(anujigh\u1E5Bk\u1E63\u0101)</em> \u0441 \u0446\u0435\u043B\u044C\u044E <em>(iti-\u0101\u015Bayata\u1E25)</em>, \u0447\u0442\u043E\u0431\u044B: &quot;\u041F\u0443\u0441\u0442\u044C \u0422\u0430\u0439\u043D\u0430\u044F <em>(rahasya)</em> \u0422\u0440\u0430\u0434\u0438\u0446\u0438\u044F <em>(samprad\u0101ya\u1E25)</em> \u043D\u0435 <em>(m\u0101)</em> \u043F\u0440\u0435\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(vicchedi)</em> \u0432 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435 <em>(loke)</em> \u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(j\u012Bva)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C <em>(pr\u0101ye)</em> \u0431\u043B\u0430\u0433\u043E\u0443\u0445\u0430\u044E\u0442 <em>(adhiv\u0101sita)</em> \u0434\u0443\u0430\u043B\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 <em>(dvaita)</em> \u0442\u043E\u0447\u043A\u043E\u0439 \u0437\u0440\u0435\u043D\u0438\u044F <em>(dar\u015Bana)</em>!&quot;; \u0440\u0430\u0441\u0448\u0438\u0440\u0438\u043B <em>(unmi\u1E63ita... k\u1E5Bta\u1E25)</em> \u0432\u043E \u0441\u043D\u0435 <em>(svapne)</em> \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(pratibha\u1E25)</em> \u044D\u0442\u043E\u0433\u043E [\u0412\u0430\u0441\u0443\u0433\u0443\u043F\u0442\u044B] <em>(asau)</em>, \u0434\u0430\u0440\u043E\u0432\u0430\u0432 \u0435\u043C\u0443 \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u041C\u0438\u043B\u043E\u0441\u0442\u044C <em>(anugrahya)</em>. [\u041E\u043D \u0441\u043A\u0430\u0437\u0430\u043B \u0435\u043C\u0443] \u0442\u0430\u043A <em>(yath\u0101... iti)</em>:</p><blockquote><p>&quot;\u0417\u0434\u0435\u0441\u044C <em>(atra)</em>, \u043D\u0430 \u044D\u0442\u043E\u0439 \u0433\u043E\u0440\u0435 <em>(mah\u012Bbh\u1E5Bti)</em>, \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F <em>(asti)</em> \u0421\u0435\u043A\u0440\u0435\u0442\u043D\u043E\u0435 \u042D\u0437\u043E\u0442\u0435\u0440\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0423\u0447\u0435\u043D\u0438\u0435 <em>(rahasyam)</em> \u043F\u043E\u0434 <em>(tale)</em> \u0431\u043E\u043B\u044C\u0448\u0438\u043C <em>(mahati)</em> \u043A\u0430\u043C\u043D\u0435\u043C <em>(\u015Bil\u0101)</em>. \u041F\u043E\u043B\u0443\u0447\u0438\u0432 \u0435\u0433\u043E <em>(tad adhigamya)</em>, \u0440\u0430\u0441\u043A\u0440\u043E\u0439 \u0435\u0433\u043E <em>(prak\u0101\u015Baya)</em> \u0442\u0435\u043C, \u043A\u0442\u043E \u043F\u043E\u0434\u0445\u043E\u0434\u0438\u0442 <em>(yogye\u1E63u)</em> \u0434\u043B\u044F \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u041C\u0438\u043B\u043E\u0441\u0442\u0438 <em>(anugraha)</em>&quot;.</p></blockquote><p>\u041F\u0440\u043E\u0441\u043D\u0443\u0432\u0448\u0438\u0441\u044C <em>(prabuddha\u1E25 ca)</em>, \u043E\u043D --\u0442.\u0435. \u0412\u0430\u0441\u0443\u0433\u0443\u043F\u0442\u0430-- <em>(asau)</em> \u043D\u0430\u0447\u0430\u043B \u0438\u0441\u043A\u0430\u0442\u044C <em>(anvi\u1E63yan)</em> \u044D\u0442\u043E\u0442 <em>(t\u0101m)</em> \u0431\u043E\u043B\u044C\u0448\u043E\u0439 <em>(mahat\u012Bm)</em> \u043A\u0430\u043C\u0435\u043D\u044C <em>(\u015Bil\u0101m)</em>. [\u0418 \u043D\u0430\u0439\u0434\u044F,] \u043E\u043D \u043F\u043E\u0432\u0435\u0440\u043D\u0443\u043B \u0435\u0433\u043E <em>(parivartanata\u1E25)</em> \u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C <em>(m\u0101tra)</em> \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435\u043C <em>(spar\u015Bana)</em> \u0440\u0443\u043A\u0438 <em>(kara)</em> \u0438 \u0443\u0432\u0438\u0434\u0435\u043B \u0441\u0432\u043E\u0438\u043C\u0438 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0433\u043B\u0430\u0437\u0430\u043C\u0438 <em>(pratyak\u1E63\u012Bk\u1E5Btya)</em>, (\u0447\u0442\u043E) \u0441\u043E\u043D <em>(svapn\u0101m)</em> \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0434\u0438\u043B\u0441\u044F <em>(sa\u1E41v\u0101d\u012Bk\u1E5Bta)</em>. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043E\u043D <em>(tatas)</em> \u043F\u043E\u043B\u0443\u0447\u0438\u043B <em>(sam\u0101sas\u0101da)</em> \u044D\u0442\u0438 <em>(im\u0101ni)</em> \u0410\u0444\u043E\u0440\u0438\u0437\u043C\u044B <em>(s\u016Btr\u0101\u1E47i)</em> \u0428\u0438\u0432\u044B <em>(\u015Biva)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 <em>(r\u016Bp\u0101\u1E47i)</em> \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043A\u0440\u0430\u0442\u043A\u0438\u043C \u0438\u0437\u043B\u043E\u0436\u0435\u043D\u0438\u0435\u043C <em>(sa\u1E45graha)</em> \u0422\u0430\u0439\u043D\u043E\u0433\u043E \u0423\u0447\u0435\u043D\u0438\u044F <em>(upani\u1E63ad)</em> \u0428\u0438\u0432\u044B <em>(\u015Biva)</em>.</p><p>\u0418 <em>(ca)</em>, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E <em>(samyak)</em> \u0438\u0437\u0443\u0447\u0438\u0432 \u0438\u0445 <em>(et\u0101ni... adhigamya)</em>, \u043E\u043D \u0440\u0430\u0441\u043A\u0440\u044B\u043B \u0438\u0445 <em>(et\u0101ni... prak\u0101\u015Bitav\u0101n)</em> \u0442\u0430\u043A\u0438\u043C \u0432\u044B\u0434\u0430\u044E\u0449\u0438\u043C\u0441\u044F <em>(sad)</em> \u0443\u0447\u0435\u043D\u0438\u043A\u0430\u043C <em>(\u015Bi\u1E63ye\u1E63u)</em>, [\u043A\u0430\u043A] \u043D\u0430\u0438\u043F\u043E\u0447\u0442\u0435\u043D\u043D\u0435\u0439\u0448\u0438\u0439 <em>(bha\u1E6D\u1E6Da\u015Br\u012B)</em> \u041A\u0430\u043B\u043B\u0430\u0442\u0430 <em>(kalla\u1E6Da)</em> \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 <em>(\u0101dye\u1E63u)</em>, \u0438 <em>(ca)</em> \u0441\u043E\u0431\u0440\u0430\u043B \u0438\u0445 <em>(et\u0101ni... sa\u1E45g\u1E5Bh\u012Btav\u0101n)</em> \u0432 \u0432\u0438\u0434\u0435 Spandak\u0101rik\u0101-s <em>(spandak\u0101rik\u0101bhi\u1E25)</em>. \u0410\u0444\u043E\u0440\u0438\u0437\u043C\u044B <em>(s\u016Btr\u0101\u1E47i)</em>, \u043A\u0430\u0441\u0430\u044E\u0449\u0438\u0435\u0441\u044F \u0418\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0412\u0438\u0431\u0440\u0430\u0446\u0438\u0438 <em>(spanda)</em> --\u0442.\u0435. Spandak\u0101rik\u0101-s, \u0438\u043B\u0438 Spandas\u016Btra-s--, \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u044B\u0435 <em>(pr\u0101pt\u0101ni)</em> \u0438\u0437 \u044D\u0442\u043E\u0439 <em>(tad)</em> \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u0439 \u0443\u0447\u0435\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u043F\u0440\u0435\u0435\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(panorama)</em>, \u0431\u044B\u043B\u0438 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E <em>(samyak)</em> \u0443\u0434\u043E\u0441\u0442\u043E\u0432\u0435\u0440\u0435\u043D\u044B <em>(nir\u1E47\u012Bt\u0101ni)</em> \u043D\u0430\u043C\u0438 <em>(asm\u0101bhi\u1E25)</em> \u0432 Spandanir\u1E47aya <em>(spandanir\u1E47aye)</em>. \u0410 \u0441\u0435\u0439\u0447\u0430\u0441 <em>(tu)</em>, \u015Aivas\u016Btra-s <em>(\u015Bivas\u016Btr\u0101\u1E47i)</em> \u043F\u0440\u043E\u044F\u0441\u043D\u044F\u044E\u0442\u0441\u044F <em>(nir\u1E47\u012Byante)</em>.</p><p>\u0412 \u043D\u0438\u0445 --\u0442.\u0435. \u0432 \u015Aivas\u016Btra-s-- <em>(tatra)</em>, \u0432 \u043F\u0435\u0440\u0432\u0443\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C <em>(prathamam)</em> \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u044F\u0435\u0442\u0441\u044F <em>(\u0101di\u015Bati)</em>, \u0432 \u043F\u043E\u043B\u043D\u043E\u0439 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u043F\u043E\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u0438 <em>(pr\u0101tipak\u1E63ye\u1E47a)</em> \u0434\u043B\u044F \u0442\u0435\u0445, \u043A\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0443\u0447\u0435\u043D\u0438\u044E <em>(v\u0101di)</em> \u043E \u0440\u0430\u0437\u043D\u0438\u0446\u0435 <em>(bheda)</em> \u043C\u0435\u0436\u0434\u0443 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u043E\u043C <em>(nara)</em> \u0438 \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C <em>(\u012B\u015Bvara)</em>, \u0447\u0442\u043E &quot;\u0428\u0438\u0432\u0430 <em>(\u015Biva\u1E25)</em> \u043E\u0434\u0438\u043D <em>(eva)</em>, (\u0438) \u0432 \u0432\u044B\u0441\u0448\u0435\u043C \u0441\u043C\u044B\u0441\u043B\u0435 <em>(param\u0101rthatas)</em> [\u0441\u043B\u043E\u0432\u0430], \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(caitanya)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0412\u044B\u0441\u0448\u0438\u043C \u042F <em>(\u0101tm\u0101)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bvasya... iti)</em>&quot;</p></div>',3),s=[r];function n(d,h,v,p,y,c){return m(),e("div",null,s)}var k=a(i,[["render",n]]);export{o as __pageData,k as default};
